// CONFIGURE HERE
var ALPACA_KEY_ID     = 'PASTE_YOUR_KEY_ID_HERE';
var ALPACA_SECRET_KEY = 'PASTE_YOUR_SECRET_KEY_HERE';
var FMP_API_KEY       = 'PASTE_YOUR_FMP_KEY_HERE';
var MAX_POSITIONS     = 3;

// Time gate: 4am–11am ET only — afternoon signals lack volume to reach T1/T2/T3
// EDT = UTC-4 → 4am ET = UTC 08:00, 11am ET = UTC 15:00
var now = new Date();
var utcHour = now.getUTCHours();
if (utcHour < 8 || utcHour >= 15) return [];

var alpacaHeaders = {
  'APCA-API-KEY-ID': ALPACA_KEY_ID,
  'APCA-API-SECRET-KEY': ALPACA_SECRET_KEY
};

// Check current positions (cap at MAX_POSITIONS)
var heldTickers = [];
try {
  var pos = await $helpers.httpRequest({
    method: 'GET',
    url: 'https://paper-api.alpaca.markets/v2/positions',
    headers: alpacaHeaders
  });
  for (var pi = 0; pi < pos.length; pi++) heldTickers.push(pos[pi].symbol);
} catch(err) {}
if (heldTickers.length >= MAX_POSITIONS) return [];

// FMP real-time gainers — pre-filter by price, change%, absolute volume
var candidates = [];
try {
  var gainers = await $helpers.httpRequest({
    method: 'GET',
    url: 'https://financialmodelingprep.com/api/v3/stock_market/gainers?apikey=' + FMP_API_KEY
  });
  for (var gi = 0; gi < gainers.length; gi++) {
    var g = gainers[gi];
    var price = g.price || 0;
    var chg   = g.changesPercentage || g.changePercent || 0;
    var vol   = g.volume || 0;
    if (price < 0.10 || price > 5.0) continue;   // $0.10–$5 universe
    if (chg < 10.0) continue;                      // min +10% gain
    if (vol < 1000000) continue;                    // absolute vol >1M (no dead stocks)
    candidates.push(g.symbol);
    if (candidates.length >= 20) break;
  }
} catch(e) { return []; }

if (candidates.length === 0) return [];

// ── INDICATOR FUNCTIONS ────────────────────────────────────────────────────

function emaArr(vals, p) {
  var k = 2 / (p + 1), r = [vals[0]];
  for (var i = 1; i < vals.length; i++) r.push(vals[i] * k + r[i-1] * (1 - k));
  return r;
}

function calcRSI(closes, p) {
  var ch = [];
  for (var i = 1; i < closes.length; i++) ch.push(closes[i] - closes[i-1]);
  var ag = 0, al = 0;
  for (var i = 0; i < p; i++) { if (ch[i] > 0) ag += ch[i]; else al -= ch[i]; }
  ag /= p; al /= p;
  var out = [];
  for (var i = p; i < ch.length; i++) {
    ag = (ag * (p-1) + Math.max(ch[i], 0)) / p;
    al = (al * (p-1) + Math.max(-ch[i], 0)) / p;
    out.push(al === 0 ? 100 : 100 - 100 / (1 + ag / al));
  }
  return out;
}

function calcStochRSI(closes) {
  var rp = 14, sp = 14, ks = 3, ds = 3;
  var rsi = calcRSI(closes, rp);
  if (rsi.length < sp + ks + ds) return null;
  var rawK = [];
  for (var i = sp-1; i < rsi.length; i++) {
    var sl = rsi.slice(i-sp+1, i+1);
    var lo = sl[0], hi = sl[0];
    for (var j = 1; j < sl.length; j++) { if (sl[j] < lo) lo = sl[j]; if (sl[j] > hi) hi = sl[j]; }
    rawK.push(hi === lo ? 0 : (rsi[i] - lo) / (hi - lo) * 100);
  }
  var sK = [];
  for (var i = ks-1; i < rawK.length; i++) {
    var s = 0; for (var j = i-ks+1; j <= i; j++) s += rawK[j]; sK.push(s / ks);
  }
  var sD = [];
  for (var i = ds-1; i < sK.length; i++) {
    var s = 0; for (var j = i-ds+1; j <= i; j++) s += sK[j]; sD.push(s / ds);
  }
  if (sK.length < 2 || sD.length < 1) return null;
  return { k: sK[sK.length-1], kPrev: sK[sK.length-2], d: sD[sD.length-1] };
}

function calcZLSMA(closes, p) {
  if (closes.length < p * 2) return null;
  var e1 = emaArr(closes, p), e2 = emaArr(e1, p);
  return 2 * e1[e1.length-1] - e2[e2.length-1];
}

function calcMACD(closes) {
  if (closes.length < 35) return null;
  var ema12 = emaArr(closes, 12), ema26 = emaArr(closes, 26);
  var macdLine = [];
  for (var i = 0; i < closes.length; i++) macdLine.push(ema12[i] - ema26[i]);
  var sig = emaArr(macdLine, 9);
  return macdLine[macdLine.length-1] - sig[sig.length-1];
}

function calcSupertrend(bars, period, mult) {
  // ATR Period=10, Source=hl2, Multiplier=2 — matches W118 Supertrend settings
  if (bars.length < period + 2) return null;
  var trs = [];
  for (var i = 1; i < bars.length; i++) {
    var h = bars[i].h, l = bars[i].l, pc = bars[i-1].c;
    trs.push(Math.max(h - l, Math.abs(h - pc), Math.abs(l - pc)));
  }
  // Wilder's smoothing
  var atr = new Array(trs.length).fill(0);
  var initSum = 0;
  for (var i = 0; i < period; i++) initSum += trs[i];
  atr[period-1] = initSum / period;
  for (var i = period; i < trs.length; i++) atr[i] = (atr[i-1] * (period-1) + trs[i]) / period;
  // atr[i] is ATR computed through bars[i+1]
  var ub = new Array(bars.length).fill(0);
  var lb = new Array(bars.length).fill(0);
  var dir = new Array(bars.length).fill(1);
  for (var i = period; i < bars.length; i++) {
    var a = atr[i-1];
    var hl2 = (bars[i].h + bars[i].l) / 2;
    var rawUb = hl2 + mult * a, rawLb = hl2 - mult * a;
    if (i === period) { ub[i] = rawUb; lb[i] = rawLb; dir[i] = 1; continue; }
    // Band persistence: upper tightens, lower raises
    ub[i] = (rawUb < ub[i-1] || bars[i-1].c > ub[i-1]) ? rawUb : ub[i-1];
    lb[i] = (rawLb > lb[i-1] || bars[i-1].c < lb[i-1]) ? rawLb : lb[i-1];
    // Direction flip on breakout
    if      (dir[i-1] === -1 && bars[i].c > ub[i]) dir[i] = 1;   // flip bullish
    else if (dir[i-1] ===  1 && bars[i].c < lb[i]) dir[i] = -1;  // flip bearish
    else dir[i] = dir[i-1];
  }
  return dir[bars.length-1]; // 1 = bullish (green), -1 = bearish (red)
}

// ── SCAN LOOP ──────────────────────────────────────────────────────────────

var signals = [];

for (var ci = 0; ci < candidates.length; ci++) {
  var ticker = candidates[ci];
  if (heldTickers.indexOf(ticker) >= 0) continue;
  if (heldTickers.length + signals.length >= MAX_POSITIONS) break;

  try {
    var barsData = await $helpers.httpRequest({
      method: 'GET',
      url: 'https://data.alpaca.markets/v2/stocks/' + ticker + '/bars?timeframe=5Min&limit=100&feed=iex&adjustment=raw',
      headers: alpacaHeaders
    });
    var bars = barsData.bars;
    if (!bars || bars.length < 60) continue;

    var closes = [];
    for (var i = 0; i < bars.length; i++) closes.push(bars[i].c);
    var price = closes[closes.length-1];
    if (price < 0.10 || price > 5.0) continue;

    // 1. Supertrend bullish — PRIMARY trigger (ATR 10, hl2, mult 2)
    var stDir = calcSupertrend(bars, 10, 2);
    if (stDir !== 1) continue;

    // 2. StochRSI K > D
    var srsi = calcStochRSI(closes);
    if (!srsi || srsi.k <= srsi.d) continue;

    // 3. Price above ZLSMA-50
    var zlsma = calcZLSMA(closes, 50);
    if (!zlsma || price <= zlsma) continue;

    // 4. MACD histogram > 0 (momentum building, not fading)
    var macdHist = calcMACD(closes);
    if (macdHist === null || macdHist <= 0) continue;

    // 5. Volume > 4x 20-bar average
    var vols = [];
    for (var i = bars.length-21; i < bars.length-1; i++) vols.push(bars[i].v);
    var avgVol = 0;
    for (var i = 0; i < vols.length; i++) avgVol += vols[i];
    avgVol /= vols.length;
    var curVol = bars[bars.length-1].v;
    if (curVol < avgVol * 4.0) continue;

    signals.push({
      json: {
        ticker:     ticker,
        price:      price,
        stop:       parseFloat((price * 0.92).toFixed(4)),
        t1:         parseFloat((price * 1.15).toFixed(4)),
        t2:         parseFloat((price * 1.30).toFixed(4)),
        t3:         parseFloat((price * 1.60).toFixed(4)),
        qty:        10,
        qty_t1:     3,
        qty_t2:     3,
        qty_t3:     4,
        k:          srsi.k.toFixed(1),
        d:          srsi.d.toFixed(1),
        macd_hist:  macdHist.toFixed(4),
        vol_ratio:  (curVol / avgVol).toFixed(1),
        deep_reset: srsi.kPrev < 15,
        ALPACA_KEY_ID:     ALPACA_KEY_ID,
        ALPACA_SECRET_KEY: ALPACA_SECRET_KEY
      }
    });
  } catch(e) {}
}

return signals;

